getStreet(pt: any): string {
  const addr = pt?.address || pt?.name || '';
  if (!addr) return '';
  const parts = addr.split(',').map((s: string) => s.trim()).filter(Boolean);
  const first = parts[0] || '';
  const m = first.match(/^(.*\D)\s+(\d+\S*)$/);
  if (m) return m[1].trim();
  if (parts.length >= 2 && /^\d+\S*$/.test(parts[0])) return parts[1];
  return first;
}

getCivic(pt: any): string {
  const addr = pt?.address || '';
  if (!addr) return '';
  const parts = addr.split(',').map((s: string) => s.trim()).filter(Boolean);
  const first = parts[0] || '';
  const m = first.match(/^(.*\D)\s+(\d+\S*)$/);
  if (m) return m[2].trim();
  if (parts.length >= 2 && /^\d+\S*$/.test(parts[0])) return parts[0];
  if (parts.length >= 2 && /^\d+\S*$/.test(parts[1])) return parts[1];
  return '';
}

getCityProvince(pt: any): string {
  const cityField = pt?.city || '';
  const provinceField = pt?.province || '';
  if (cityField || provinceField) {
    return `${cityField}${provinceField && cityField !== provinceField ? ' ' + provinceField : ''}`.trim();
  }
  const addr = pt?.address || '';
  if (!addr) return '';
  const parts = addr.split(',').map((s: string) => s.trim()).filter(Boolean);
  const countryTokens = ['italia', 'italy'];
  while (parts.length && countryTokens.includes(parts[parts.length - 1].toLowerCase())) parts.pop();
  while (parts.length && /^\d{4,}$/.test(parts[parts.length - 1])) parts.pop();
  const street = this.getStreet(pt);
  const civic = this.getCivic(pt);
  for (let i = parts.length - 1; i >= 0; i--) {
    const p = parts[i];
    if (!p) continue;
    if (p === street || p === civic) continue;
    if (/^\d+$/.test(p) || p.length > 40) continue;
    return p;
  }
  return '';
}

// Metodo per resettare gli orari di apertura
resetOrariDefault(): void {
  const defaultSlots = {
    monday: [{ open: '09:00', close: '18:00' }],
    tuesday: [{ open: '09:00', close: '18:00' }],
    wednesday: [{ open: '09:00', close: '18:00' }],
    thursday: [{ open: '09:00', close: '18:00' }],
    friday: [{ open: '09:00', close: '18:00' }],
    saturday: [{ open: '09:00', close: '13:00' }],
    sunday: []
  };
  this.giorniSettimana.forEach(d => {
    const dayGroup = this.getDayGroup(d.key);
    dayGroup.get('closed')?.patchValue(defaultSlots[d.key as keyof typeof defaultSlots].length === 0);
    const slotsArray = dayGroup.get('slots') as FormArray;
    slotsArray.clear();
    defaultSlots[d.key as keyof typeof defaultSlots].forEach(s => {
      slotsArray.push(this.fb.group({
        open: s.open,
        close: s.close
      }));
    });
  });
  this.messaggioSuccesso = 'Orari reimpostati ai valori predefiniti';
  this.nascondiMessaggio();
}

// Helper per formattare i giorni di chiusura nel template
formatClosedDay(cd: ClosedDay): string {
  if (!cd) return '';
  if (cd.type === 'range') {
    return `${this.formatDateDisplay(cd.start)} → ${this.formatDateDisplay(cd.end)}`;
  }
  return this.formatDateDisplay(cd.start);
}

